noncompliant:
chdir("/home/user");
// Noncompliant: no verification if directory change succeeded
open("relative/file.txt", O_RDONLY);

compliant:
const char* any_dir = "/any/";
if (chdir(any_dir) != 0) {
  perror("chdir failed");
  exit(1);
}

int fd = open("/tmp", O_RDONLY | O_DIRECTORY);
if (fd != -1) {
  if (fchdir(fd) != 0) {
    perror("fchdir failed");
    close(fd);
    exit(1);
  }
  close(fd);
}

if (chdir("/home/user") == 0) {
  // Compliant: verified directory change succeeded
  int fd = open("relative/file.txt", O_RDONLY);
} else {
  fprintf(stderr, "Failed to change directory");
}
